INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-e7b0146b-moex-00080', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-15fd680d', 'sub-locality-e7b0146b-04', NULL, 'essay', '黃土水（1895～1930）為臺灣美術史上第一位入選帝展的雕刻家，其生
涯雖然短暫，卻留下諸多精彩傑作如《甘露水》、《釋迦出山》（重要古物）
或《南國（水牛群像）》（國寶），成為不朽經典。請以最近重新出土之《甘
露水》一作為中心，試論黃土水的整體創作理念，與其呼籲建構「福爾
摩沙藝術」及彰顯臺灣地方性價值的想法有何關聯？同時對形塑當代文
化認同有何啟示作用？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "b85ff88d39d5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "藝術概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00081', 'locality-e7b0146b', 'locality-e7b0146b-moex-111-15fd680d', 'sub-locality-e7b0146b-04', NULL, 'essay', '進入二十世紀之後，兩次史無前例之世界大戰造成極大傷害，過往諸多
國家觀念、社會價值及倫常秩序等產生動搖，各種主義理論及藝術思想
大行其道，又彼此消長快速，分庭抗禮者眾，成為「現代藝術」（Modern
Art）發展上的特殊現象。請根據您對此階段西方「現代藝術」歷史發展
之理解，列舉二個流派或主義之作品進行比對分析，檢視其時代特質、
主要理論之觀念內容、作品風格之個別特徵，以及不同國家或地區「現
代藝術」有何根本性的差異。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "b85ff88d39d5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "308", "s": "0305", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "藝術概論", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00082', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-8a180e95', 'sub-locality-e7b0146b-05', NULL, 'essay', '從中世紀後期到近代，歐洲經濟重心歷經轉移，促成不同商業霸權的興
衰。在霸權興衰過程中，中世紀後期義大利威尼斯（Venice）、十七世紀
荷蘭阿姆斯特丹（Amsterdam）、十九世紀英國倫敦（London），先後興起
為商業與金融重心。請從中世紀後期以來歐洲經濟形勢的變動，試論這
三個城市的興衰變化。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "4814e5b73435", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界文化史", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00083', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-8a180e95', 'sub-locality-e7b0146b-05', NULL, 'essay', '西元 476 年，日耳曼傭兵首領奧德阿瑟（Odoacer,c.435-493）廢黜羅馬
最後一位皇帝奧古斯都拉（RomulusAugustuslus），西羅馬帝國滅亡，
結束了歐洲史上的古典時代。西羅馬帝國何以衰亡？這一課題曾引起眾
多史家的興趣與討論。請分析造成西羅馬帝國衰亡的各種因素。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "4814e5b73435", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界文化史", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00084', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-8a180e95', 'sub-locality-e7b0146b-05', NULL, 'essay', '第二次世界大戰結束後，歐洲的殖民主義退潮。戰後 20年間，獨立運動
在各殖民地風起雲湧，出現眾多的新興國家。請說明戰後歐洲殖民主義
退潮的原因為何？各殖民地母國如何應對此一殖民地獨立浪潮？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "4814e5b73435", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界文化史", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00085', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-8a180e95', 'sub-locality-e7b0146b-05', NULL, 'essay', '二十世紀以來，世界文化的發展趨勢是從傳統的「精緻文化」（refined
culture）走向「大眾文化」（mass culture）。大眾文化的興起與盛行，乃
是二十世紀世界文化的重要現象。請說明二十世紀「大眾文化」興起的
背景為何？二十世紀的大眾文化有那些重要特徵？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "4814e5b73435", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "世界文化史", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00086', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-c8ef209c', 'sub-locality-e7b0146b-01', NULL, 'essay', '1960～1990 年代，歐美文化人類學者為探索族群（ethnicgroup）和族
群意識／族群性（ethnicity）本質，提出「根本賦與論／根基論
（primordialism）」與「環境情境決定論／工具論（circumstantialism/
situationism/instrumentalism）」等兩大類型論述，請申論這兩類理論之重
要代表作者及理論要旨為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "c0184535073e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化人類學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00087', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-c8ef209c', 'sub-locality-e7b0146b-01', NULL, 'essay', '從歐美日等國的人類學與博物館學專業發展過程來看，人類學與博物館
的關係可說十分密切。請以文化部所管轄的兩間重要文化機構—國立臺
灣博物館與國立臺灣史前文化博物館為例，申論人類學知識如何應用於
這兩間博物館？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:41+00:00", "source_pdf_sha1": "c0184535073e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "307", "s": "0203", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "文化人類學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "文化行政"}'::jsonb, NULL),
  ('locality-e7b0146b-moex-00088', 'locality-e7b0146b', 'locality-e7b0146b-moex-110-c8ef209c', 'sub-locality-e7b0146b-01', NULL, 'essay', '何謂藝術人類學？藝術作品的形式、材料及圖案等如何受到當地環境及
